update stations s set parish_id = v.parish_id from (values
  ('830ef604-20cc-4f04-bbe8-19ee7d8cc8b2'::uuid, 355043),
  ('e7f955ce-4ccb-48eb-b3cb-b107105fb392'::uuid, 354495),
